def coroutine(func):
    def wrapper(*args, **kwargs):
        gen = func(*args, **kwargs)
        next(gen)  # prime the coroutine
        return gen
    return wrapper

@coroutine
def filter_stage(predicate, target):
    while True:
        item = yield
        if predicate(item):
            target.send(item)

@coroutine
def transform_stage(func, target):
    while True:
        item = yield
        target.send(func(item))

@coroutine
def sink(callback):
    results = []
    try:
        while True:
            item = yield
            results.append(item)
    except GeneratorExit:
        callback(results)

