class Validated:
    def __init__(self, type_=None, min_val=None, max_val=None):
        self.type_ = type_
        self.min_val = min_val
        self.max_val = max_val

    def __set_name__(self, owner, name):
        self.name = name
        self.storage_name = f'_validated_{name}'

    def __get__(self, obj, objtype=None):
        if obj is None: return self
        return getattr(obj, self.storage_name, None)

    def __set__(self, obj, value):
        if self.type_ and not isinstance(value, self.type_):
            raise TypeError(f'{self.name} must be {self.type_.__name__}')
        if self.min_val is not None and value < self.min_val:
            raise ValueError(f'{self.name} must be >= {self.min_val}')
        if self.max_val is not None and value > self.max_val:
            raise ValueError(f'{self.name} must be <= {self.max_val}')
        setattr(obj, self.storage_name, value)

class Product:
    name = Validated(type_=str)
    price = Validated(type_=(int, float), min_val=0)
    quantity = Validated(type_=int, min_val=0, max_val=10000)

    def __init__(self, name, price, quantity):
        self.name = name
        self.price = price
        self.quantity = quantity
